class Solution:
    def minimumSubstringsInPartition(self, s: str) -> int:
        n = len(s)
        dp = [float('inf')] * (n+1)
        dp[0] = 0
        for i in range(1, n+1):
            freq = {}
            max_freq = 0
            distinct = 0
            for j in range(i-1, -1, -1):
                c = s[j]
                freq[c] = freq.get(c, 0) + 1
                if freq[c] == 1:
                    distinct += 1
                max_freq = max(max_freq, freq[c])
                length = i - j
                # balanced iff all freqs equal: distinct * max_freq == length
                if distinct * max_freq == length and dp[j] < float('inf'):
                    dp[i] = min(dp[i], dp[j] + 1)
        return dp[n]

