var minimumSubstringsInPartition = function(s) {
    const n = s.length;
    const dp = new Array(n+1).fill(Infinity);
    dp[0] = 0;
    for (let i = 1; i <= n; i++) {
        const freq = {};
        let maxFreq = 0, distinct = 0;
        for (let j = i-1; j >= 0; j--) {
            const c = s[j];
            freq[c] = (freq[c] || 0) + 1;
            if (freq[c] === 1) distinct++;
            if (freq[c] > maxFreq) maxFreq = freq[c];
            const length = i - j;
            if (distinct * maxFreq === length && dp[j] < Infinity) {
                dp[i] = Math.min(dp[i], dp[j] + 1);
            }
        }
    }
    return dp[n];
};
